import React from 'react';

const Home = () => {
  return (
    <div style={{
      padding: '80px',
      backgroundColor: '#e6f3ff',
      minHeight: '100vh',
      fontSize: '32px',
      color: '#004080',
      textAlign: 'center'
    }}>
      <h1>HELLO ABHISHEK</h1>
      <p style={{ fontSize: '24px' }}>
        If you see this blue background + big text → rendering works.<br />
        The problem is inside one of the real components.
      </p>
    </div>
  );
};

export default Home;
